// Extract clean text from a DOMParser-created document.
// innerText DOES NOT work in DOMParser docs (requires layout engine).
// We use textContent but clean up script/style noise manually.
function extractDocText(doc) {
  if (!doc || !doc.body) return "";
  // Remove script and style elements
  const clone = doc.body.cloneNode(true);
  clone.querySelectorAll("script, style, noscript").forEach(el => el.remove());
  // Replace <br> and block elements with newlines
  clone.querySelectorAll("br, p, div, tr, li").forEach(el => {
    el.insertAdjacentText("beforebegin", "\n");
  });
  // Replace <td> and <th> with tab separator
  clone.querySelectorAll("td, th").forEach(el => {
    el.insertAdjacentText("afterend", "\t");
  });
  return clone.textContent.replace(/\t\n/g, "\n").replace(/\n{3,}/g, "\n\n").trim();
}

