// Capture and block native link navigations that open in new tabs during active scraping
window.addEventListener("click", (e) => {
  const isActive = document.documentElement.getAttribute("data-mandi-scraper-active") === "true";
  if (!isActive) return;

  const link = e.target.closest("a");
  if (link) {
    const href = link.getAttribute("href");
    if (href && href !== "#" && !href.startsWith("javascript:")) {
      e.preventDefault();
      console.log("eMandi Content: Blocked native link navigation to URL:", href);
      window.dispatchEvent(new CustomEvent("eMandiOpenIntercepted", { detail: { url: href } }));
    }
  }
}, { capture: true });

