function getPaymentFormInputs() {
  const inputs = {
    accountNo: null,
    ifsc: null,
    transactionNo: null,
    amount: null,
    date: null,
    remarks: null
  };

  const allLabels = Array.from(document.querySelectorAll("label, span, td, div, p"));

  allLabels.forEach(el => {
    const text = el.textContent.trim();
    const findNextInput = (node) => {
      let curr = node;
      for (let i = 0; i < 4; i++) {
        if (!curr) break;
        const inp = curr.querySelector("input:not([type='hidden']), select, textarea");
        if (inp) return inp;
        curr = curr.nextElementSibling || curr.parentElement;
      }
      return null;
    };

    if (text.includes("बैंक खाता संख्या") || text.includes("खाता संख्या") || text.includes("Account Number")) {
      if (!inputs.accountNo) inputs.accountNo = findNextInput(el);
    }
    if (text.includes("IFSC") || text.includes("आईएफएससी") || text.includes("IFSC कोड")) {
      if (!inputs.ifsc) inputs.ifsc = findNextInput(el);
    }
    if (text.includes("ट्रांजेक्शन नंबर") || text.includes("Transaction Number") || text.includes("UTR")) {
      if (!inputs.transactionNo) inputs.transactionNo = findNextInput(el);
    }
    if (text.includes("भुगतान की राशि") || text.includes("राशि") || text.includes("Amount")) {
      if (!inputs.amount) inputs.amount = findNextInput(el);
    }
    if (text.includes("तिथि") || text.includes("Date")) {
      if (!inputs.date) inputs.date = findNextInput(el);
    }
    if (text.includes("विवरण") || text.includes("Remarks") || text.includes("Description")) {
      if (!inputs.remarks) inputs.remarks = findNextInput(el);
    }
  });

  if (!inputs.accountNo) {
    inputs.accountNo = document.querySelector("input[name*='Account'], input[id*='Account'], input[name*='Bank'], input[id*='Bank']");
  }
  if (!inputs.ifsc) {
    inputs.ifsc = document.querySelector("input[name*='IFSC'], input[id*='IFSC'], input[name*='ifsc']");
  }
  if (!inputs.transactionNo) {
    inputs.transactionNo = document.querySelector("input[name*='Transaction'], input[id*='Transaction'], input[name*='UTR'], input[id*='UTR']");
  }
  if (!inputs.amount) {
    inputs.amount = document.querySelector("input[name*='Amount'], input[id*='Amount'], input[name*='Payment'], input[id*='Payment']");
  }

  return inputs;
}

function initBankDetailsFiller() {
  const url = window.location.href;
  if (!url.includes("SixRPaymentmaster")) return;

  console.log("eMandi Content: Initializing Bank Details Filler UI...");

  chrome.storage.local.get({ supplier_bank_accounts: [] }, (result) => {
    const accounts = result.supplier_bank_accounts;
    console.log("eMandi Content: Loaded supplier bank accounts for UI:", accounts.length);

    const container = document.createElement("div");
    container.id = "emandi-bank-filler-widget";
    container.style.position = "fixed";
    container.style.top = "80px";
    container.style.right = "20px";
    container.style.width = "350px";
    container.style.maxHeight = "80vh";
    container.style.backgroundColor = "#1e293b";
    container.style.color = "#ffffff";
    container.style.borderRadius = "12px";
    container.style.boxShadow = "0 10px 25px -5px rgba(0, 0, 0, 0.3), 0 8px 10px -6px rgba(0, 0, 0, 0.3)";
    container.style.border = "1px solid #334155";
    container.style.zIndex = "999999";
    container.style.fontFamily = "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif";
    container.style.display = "flex";
    container.style.flexDirection = "column";
    container.style.overflow = "hidden";

    const header = document.createElement("div");
    header.style.padding = "16px";
    header.style.backgroundColor = "#0f172a";
    header.style.borderBottom = "1px solid #334155";
    header.style.display = "flex";
    header.style.justifyContent = "space-between";
    header.style.alignItems = "center";

    const title = document.createElement("h3");
    title.innerText = "बैंक खाता सूची (Quick Fill)";
    title.style.margin = "0";
    title.style.fontSize = "16px";
    title.style.fontWeight = "600";
    title.style.color = "#38bdf8";

    const badge = document.createElement("span");
    badge.innerText = `${accounts.length} Accounts`;
    badge.style.fontSize = "11px";
    badge.style.backgroundColor = "#0369a1";
    badge.style.padding = "2px 8px";
    badge.style.borderRadius = "12px";
    badge.style.color = "#e0f2fe";

    header.appendChild(title);
    header.appendChild(badge);
    container.appendChild(header);

    const searchWrapper = document.createElement("div");
    searchWrapper.style.padding = "10px 16px";
    searchWrapper.style.backgroundColor = "#1e293b";
    searchWrapper.style.borderBottom = "1px solid #334155";

    const searchInput = document.createElement("input");
    searchInput.type = "text";
    searchInput.placeholder = "किसान का नाम या खाता संख्या खोजें...";
    searchInput.style.width = "100%";
    searchInput.style.padding = "8px 12px";
    searchInput.style.borderRadius = "6px";
    searchInput.style.border = "1px solid #475569";
    searchInput.style.backgroundColor = "#0f172a";
    searchInput.style.color = "#ffffff";
    searchInput.style.fontSize = "13px";
    searchInput.style.boxSizing = "border-box";
    searchInput.style.outline = "none";

    searchWrapper.appendChild(searchInput);
    container.appendChild(searchWrapper);

    const list = document.createElement("div");
    list.style.flex = "1";
    list.style.overflowY = "auto";
    list.style.padding = "10px";
    list.style.maxHeight = "50vh";

    const renderList = (filterText = "") => {
      list.innerHTML = "";
      const term = filterText.toLowerCase().trim();
      const filtered = accounts.filter(acc => {
        return (acc.accountHolderName || "").toLowerCase().includes(term) ||
               (acc.accountNumber || "").includes(term) ||
               (acc.bankName || "").toLowerCase().includes(term);
      });

      if (filtered.length === 0) {
        const noData = document.createElement("div");
        noData.innerText = "कोई बैंक खाता नहीं मिला।";
        noData.style.padding = "20px";
        noData.style.textAlign = "center";
        noData.style.color = "#94a3b8";
        noData.style.fontSize = "13px";
        list.appendChild(noData);
        return;
      }

      filtered.forEach(acc => {
        const item = document.createElement("div");
        item.style.padding = "12px";
        item.style.marginBottom = "8px";
        item.style.borderRadius = "8px";
        item.style.backgroundColor = "#334155";
        item.style.cursor = "pointer";
        item.style.transition = "all 0.2s ease";
        item.style.border = "1px solid transparent";

        item.onmouseenter = () => {
          item.style.backgroundColor = "#475569";
          item.style.borderColor = "#38bdf8";
        };
        item.onmouseleave = () => {
          item.style.backgroundColor = "#334155";
          item.style.borderColor = "transparent";
        };

        item.onclick = () => {
          const formInputs = getPaymentFormInputs();
          let filledCount = 0;

          if (formInputs.accountNo) {
            formInputs.accountNo.value = acc.accountNumber || "";
            formInputs.accountNo.dispatchEvent(new Event("input", { bubbles: true }));
            formInputs.accountNo.dispatchEvent(new Event("change", { bubbles: true }));
            filledCount++;
          }
          if (formInputs.ifsc) {
            formInputs.ifsc.value = acc.ifscCode || "";
            formInputs.ifsc.dispatchEvent(new Event("input", { bubbles: true }));
            formInputs.ifsc.dispatchEvent(new Event("change", { bubbles: true }));
            filledCount++;
          }
          if (formInputs.remarks) {
            formInputs.remarks.value = `भुगतान प्राप्तकर्ता: ${acc.accountHolderName || ""} (${acc.bankName || ""})`;
            formInputs.remarks.dispatchEvent(new Event("input", { bubbles: true }));
            formInputs.remarks.dispatchEvent(new Event("change", { bubbles: true }));
            filledCount++;
          }

          item.style.backgroundColor = "#0284c7";
          setTimeout(() => {
            item.style.backgroundColor = "#334155";
          }, 600);

          // Custom visual feedback notice (non-blocking notification inside page instead of raw alert)
          const toast = document.createElement("div");
          toast.innerText = `भरा गया: ${acc.accountHolderName || ""}`;
          toast.style.position = "fixed";
          toast.style.bottom = "20px";
          toast.style.right = "20px";
          toast.style.backgroundColor = "#10b981";
          toast.style.color = "#ffffff";
          toast.style.padding = "12px 24px";
          toast.style.borderRadius = "8px";
          toast.style.zIndex = "9999999";
          toast.style.fontWeight = "bold";
          document.body.appendChild(toast);
          setTimeout(() => toast.remove(), 2500);
        };

        const nameLine = document.createElement("div");
        nameLine.style.fontWeight = "600";
        nameLine.style.fontSize = "13.5px";
        nameLine.style.color = "#38bdf8";
        nameLine.innerText = acc.accountHolderName || "Unknown Name";

        const accLine = document.createElement("div");
        accLine.style.fontSize = "12px";
        accLine.style.color = "#e2e8f0";
        accLine.style.marginTop = "4px";
        accLine.innerText = `A/C: ${acc.accountNumber || "—"}`;

        const detailsLine = document.createElement("div");
        detailsLine.style.fontSize = "11px";
        detailsLine.style.color = "#94a3b8";
        detailsLine.style.marginTop = "4px";
        detailsLine.innerText = `IFSC: ${acc.ifscCode || "—"} | ${acc.bankName || ""}`;

        item.appendChild(nameLine);
        item.appendChild(accLine);
        item.appendChild(detailsLine);
        list.appendChild(item);
      });
    };

    searchInput.addEventListener("input", (e) => {
      renderList(e.target.value);
    });

    container.appendChild(list);

    const footer = document.createElement("div");
    footer.style.padding = "10px 16px";
    footer.style.backgroundColor = "#0f172a";
    footer.style.borderTop = "1px solid #334155";
    footer.style.fontSize = "11.5px";
    footer.style.color = "#94a3b8";
    footer.style.textAlign = "center";
    footer.innerText = "डैशबोर्ड या लोकलहोस्ट ऐप खोलने पर यह सूची स्वतः अपडेट होती है।";

    container.appendChild(footer);
    document.body.appendChild(container);
    renderList();
  });
}

