    title.innerText = "त्वरित डेटा चयन (Quick Fill)";
    title.style.margin = "0";
    title.style.fontSize = "15px";
    title.style.fontWeight = "600";
    title.style.color = "#38bdf8";

    const badge = document.createElement("span");
    badge.innerText = `${bankAccounts.length + statementRecords.length} Items`;
    badge.style.fontSize = "11px";
    badge.style.backgroundColor = "#0369a1";
    badge.style.padding = "2px 8px";
    badge.style.borderRadius = "12px";
    badge.style.color = "#e0f2fe";

    header.appendChild(title);
    header.appendChild(badge);
    container.appendChild(header);

    const searchWrapper = document.createElement("div");
    searchWrapper.style.padding = "10px 16px";
    searchWrapper.style.backgroundColor = "#1e293b";
    searchWrapper.style.borderBottom = "1px solid #334155";

    const searchInput = document.createElement("input");
    searchInput.type = "text";
    searchInput.placeholder = "किसान नाम, खाता, UTR या बैंक खोजें...";
    searchInput.style.width = "100%";
    searchInput.style.padding = "8px 12px";
    searchInput.style.borderRadius = "6px";
    searchInput.style.border = "1px solid #475569";
    searchInput.style.backgroundColor = "#0f172a";
    searchInput.style.color = "#ffffff";
    searchInput.style.fontSize = "13px";
    searchInput.style.boxSizing = "border-box";
    searchInput.style.outline = "none";

    searchWrapper.appendChild(searchInput);
    container.appendChild(searchWrapper);

    const list = document.createElement("div");
    list.style.flex = "1";
    list.style.overflowY = "auto";
    list.style.padding = "10px";
    list.style.maxHeight = "50vh";

    const cleanAmountStr = (val) => {
      if (!val) return null;
      // Remove commas
      const noCommas = val.replace(/,/g, "");
      // Extract decimal float (supports optional leading minus)
      const match = noCommas.match(/-?\d+(\.\d+)?/);
      if (match) {
        const floatVal = parseFloat(match[0]);
        return Math.round(Math.abs(floatVal));
      }
      return null;
    };

    const isNameMatch = (accName, stmtName) => {
      if (!accName || !stmtName) return false;
      const a = accName.toLowerCase().trim();
      const s = stmtName.toLowerCase().trim();
      if (a.includes(s) || s.includes(a)) return true;

      // Word-based match for words longer than 2 characters
      const wordsA = a.split(/[^a-zA-Z0-9\u0900-\u097F]/).filter(w => w.length > 2);
      const wordsS = s.split(/[^a-zA-Z0-9\u0900-\u097F]/).filter(w => w.length > 2);
      return wordsA.some(wa => wordsS.includes(wa));
    };

    const getPageAmount = () => {
      const formInputs = getPaymentFormInputs();
      return formInputs.amount ? cleanAmountStr(formInputs.amount.value) : null;
    };

    const renderList = (filterText = "") => {
      list.innerHTML = "";
      const term = filterText.toLowerCase().trim();

      const pageAmount = getPageAmount();
      console.log("eMandi Widget: Rendering list. Current Page Amount:", pageAmount, "Search Term:", term);

      // Filter D1 Bank accounts by search term
      const searchedBanks = bankAccounts.filter(acc => {
        return (acc.accountHolderName || "").toLowerCase().includes(term) ||
               (acc.accountNumber || "").includes(term) ||
               (acc.bankName || "").toLowerCase().includes(term);
      });

      // Filter Statements by search term
      const searchedStatements = statementRecords.filter(stmt => {
        return (stmt.name || "").toLowerCase().includes(term) ||
               (stmt.utr || "").toLowerCase().includes(term) ||
               (stmt.amount || "").toLowerCase().includes(term) ||
               (stmt.bankName || "").toLowerCase().includes(term) ||
               (stmt.date || "").includes(term);
      });

      // Only show recommendations if there's a page amount and search term is empty
      let recommendedStatements = [];
      let recommendedBanks = [];
      let remainingStatements = searchedStatements;
      let remainingBanks = searchedBanks;

      if (pageAmount && term === "") {
        // Find statement records matching the page amount
        recommendedStatements = statementRecords.filter(stmt => {
          return cleanAmountStr(stmt.amount) === pageAmount;
        });

        // Find bank accounts matching names or bank names of matching statements
        if (recommendedStatements.length > 0) {
          recommendedBanks = bankAccounts.filter(acc => {
            return recommendedStatements.some(stmt => isNameMatch(acc.accountHolderName, stmt.name));
          });
        }

        // Remove recommended items from remaining lists to avoid duplicate render
        remainingStatements = searchedStatements.filter(stmt => !recommendedStatements.includes(stmt));
        remainingBanks = searchedBanks.filter(acc => !recommendedBanks.includes(acc));
      }

      if (recommendedStatements.length === 0 && recommendedBanks.length === 0 && remainingBanks.length === 0 && remainingStatements.length === 0) {
        const noData = document.createElement("div");
        noData.innerText = "कोई मिलान परिणाम नहीं मिला।";
        noData.style.padding = "20px";
        noData.style.textAlign = "center";
        noData.style.color = "#94a3b8";
        noData.style.fontSize = "13px";
        list.appendChild(noData);
        return;
      }

      // Helper to append a bank account item
      const appendBankItem = (acc, isRecommended = false) => {
        const item = document.createElement("div");
        item.style.padding = "10px";
        item.style.marginBottom = "6px";
        item.style.borderRadius = "8px";
        item.style.backgroundColor = isRecommended ? "#1e3a8a" : "#334155";
        item.style.border = isRecommended ? "1px solid #3b82f6" : "1px solid transparent";
        item.style.cursor = "pointer";
        item.style.transition = "all 0.2s ease";

        item.onmouseenter = () => {
          item.style.backgroundColor = isRecommended ? "#2563eb" : "#475569";
          item.style.borderColor = "#38bdf8";
        };
        item.onmouseleave = () => {
          item.style.backgroundColor = isRecommended ? "#1e3a8a" : "#334155";
          item.style.borderColor = isRecommended ? "#3b82f6" : "transparent";
        };

        item.onclick = () => {
          const formInputs = getPaymentFormInputs();
          if (formInputs.accountNo) {
            formInputs.accountNo.value = acc.accountNumber || "";
            formInputs.accountNo.dispatchEvent(new Event("input", { bubbles: true }));
            formInputs.accountNo.dispatchEvent(new Event("change", { bubbles: true }));
            formInputs.accountNo.style.border = "2px solid #10b981";
            setTimeout(() => formInputs.accountNo.style.border = "", 1500);
          }
          if (formInputs.ifsc) {
            formInputs.ifsc.value = acc.ifscCode || "";
            formInputs.ifsc.dispatchEvent(new Event("input", { bubbles: true }));
            formInputs.ifsc.dispatchEvent(new Event("change", { bubbles: true }));
            formInputs.ifsc.style.border = "2px solid #10b981";
            setTimeout(() => formInputs.ifsc.style.border = "", 1500);
          }
          if (formInputs.remarks) {
            formInputs.remarks.value = "okk";
            formInputs.remarks.dispatchEvent(new Event("input", { bubbles: true }));
            formInputs.remarks.dispatchEvent(new Event("change", { bubbles: true }));
          }
           if (formInputs.remarksList && formInputs.remarksList.length > 0) {
            formInputs.remarksList.forEach(rInp => {
              rInp.value = "okk";
              rInp.dispatchEvent(new Event("input", { bubbles: true }));
              rInp.dispatchEvent(new Event("change", { bubbles: true }));
            });
          }
          showToastNotification(`खाता और IFSC भरा गया: ${acc.accountHolderName}`);
        };

        const recBadge = isRecommended ? `<span style="font-size: 10px; background-color: #3b82f6; color: white; padding: 1px 6px; border-radius: 4px; margin-left: 8px;">🎯 मैच</span>` : "";

        item.innerHTML = `
          <div style="font-weight: 600; font-size: 13px; color: #38bdf8; display: flex; justify-content: space-between; align-items: center;">
            <span>${acc.accountHolderName || "Unknown"}</span>
            ${recBadge}
          </div>
          <div style="font-size: 11.5px; color: #e2e8f0; margin-top: 3px;">A/C: ${acc.accountNumber || "—"}</div>
          <div style="font-size: 11px; color: #cbd5e1; margin-top: 2px;">IFSC: ${acc.ifscCode || "—"} | ${acc.bankName || ""}</div>
        `;
        list.appendChild(item);
      };

      // Helper to append a statement transaction item
      const appendStatementItem = (stmt, isRecommended = false) => {
        const item = document.createElement("div");
        item.style.padding = "10px";
        item.style.marginBottom = "6px";
        item.style.borderRadius = "8px";
        item.style.backgroundColor = isRecommended ? "#064e3b" : "#334155";
        item.style.border = isRecommended ? "1px solid #10b981" : "1px solid transparent";
        item.style.cursor = "pointer";
        item.style.transition = "all 0.2s ease";

        item.onmouseenter = () => {
          item.style.backgroundColor = isRecommended ? "#047857" : "#475569";
          item.style.borderColor = "#10b981";
        };
        item.onmouseleave = () => {
          item.style.backgroundColor = isRecommended ? "#064e3b" : "#334155";
          item.style.borderColor = isRecommended ? "#10b981" : "transparent";
        };

        item.onclick = () => {
          const formInputs = getPaymentFormInputs();
          if (formInputs.transactionNo) {
            formInputs.transactionNo.value = stmt.utr || "";
            formInputs.transactionNo.dispatchEvent(new Event("input", { bubbles: true }));
            formInputs.transactionNo.dispatchEvent(new Event("change", { bubbles: true }));
            formInputs.transactionNo.style.border = "2px solid #10b981";
            setTimeout(() => formInputs.transactionNo.style.border = "", 1500);
          }
          if (formInputs.date) {
            formInputs.date.value = stmt.date || "";
            formInputs.date.dispatchEvent(new Event("input", { bubbles: true }));
            formInputs.date.dispatchEvent(new Event("change", { bubbles: true }));
            formInputs.date.style.border = "2px solid #10b981";
            setTimeout(() => formInputs.date.style.border = "", 1500);
          }

          if (formInputs.paymentMode && stmt.description) {
            const descUpper = stmt.description.toUpperCase();
            let matchedMode = "";
            if (descUpper.includes("NEFT") || descUpper.includes("RTGS") || descUpper.includes("TRF")) {
              matchedMode = "RTGS/NEFT";
            } else if (descUpper.includes("UPI")) {
              matchedMode = "UPI";
            } else if (descUpper.includes("CARD")) {
              matchedMode = "Card Payment";
            } else if (descUpper.includes("DD")) {
              matchedMode = "DD";
            } else if (descUpper.includes("NET BANKING") || descUpper.includes("IB") || descUpper.includes("NETBANKING")) {
              matchedMode = "Net Banking";
            }

            if (matchedMode) {
              const options = Array.from(formInputs.paymentMode.options);
              const foundOpt = options.find(opt => 
                opt.text.toUpperCase().includes(matchedMode.toUpperCase()) || 
                opt.value.toUpperCase().includes(matchedMode.toUpperCase())
              );
              if (foundOpt) {
                formInputs.paymentMode.value = foundOpt.value;
                formInputs.paymentMode.dispatchEvent(new Event("change", { bubbles: true }));
                formInputs.paymentMode.style.border = "2px solid #10b981";
                setTimeout(() => formInputs.paymentMode.style.border = "", 1500);
              }
            }
          }

          showToastNotification(`UTR (${stmt.utr}), तिथि (${stmt.date}) और भुगतान विधि भरी गई!`);
        };

        const recBadge = isRecommended ? `<span style="font-size: 10px; background-color: #10b981; color: white; padding: 1px 6px; border-radius: 4px;">🎯 अमाउंट मैच</span>` : "";

        item.innerHTML = `
          <div style="display: flex; justify-content: space-between; align-items: start;">
            <div style="font-weight: 600; font-size: 12.5px; color: #10b981; font-family: monospace;">UTR: ${stmt.utr || "—"}</div>
            <div style="display: flex; flex-direction: column; align-items: end; gap: 4px;">
              <span style="font-weight: bold; font-size: 12.5px; color: #ef4444;">${stmt.amount || "—"}</span>
              ${recBadge}
            </div>
          </div>
          <div style="font-size: 11.5px; color: #e2e8f0; margin-top: 3px;">Name: ${stmt.name || "—"}</div>
          <div style="font-size: 11px; color: #cbd5e1; margin-top: 2px;">Date: ${stmt.date || "—"} | ${stmt.bankName || ""}</div>
