      if (remainingBanks.length > 0) {
        const secHeader = document.createElement("div");
        secHeader.innerText = "🏦 सभी बैंक खाते (D1 Accounts)";
        secHeader.style.padding = "4px 8px";
        secHeader.style.fontSize = "11px";
        secHeader.style.fontWeight = "bold";
        secHeader.style.color = "#cbd5e1";
        secHeader.style.backgroundColor = "#0f172a";
        secHeader.style.borderRadius = "4px";
        secHeader.style.marginTop = recommendedBanks.length > 0 ? "10px" : "0px";
        secHeader.style.marginBottom = "8px";
        bankCol.appendChild(secHeader);

        remainingBanks.forEach(acc => appendBankItem(acc, false));
      }

      if (recommendedBanks.length === 0 && remainingBanks.length === 0) {
        const noData = document.createElement("div");
        noData.innerText = "कोई बैंक खाता नहीं मिला।";
        noData.style.padding = "20px";
        noData.style.textAlign = "center";
        noData.style.color = "#94a3b8";
        noData.style.fontSize = "13px";
        bankCol.appendChild(noData);
      }

      // 2. RENDER STATEMENT COLUMN
      if (recommendedStatements.length > 0) {
        const secHeader = document.createElement("div");
        secHeader.innerText = `🎯 अनुशंसित स्टेटमेंट (${pageAmount} के लिए)`;
        secHeader.style.padding = "4px 8px";
        secHeader.style.fontSize = "11px";
        secHeader.style.fontWeight = "bold";
        secHeader.style.color = "#10b981";
        secHeader.style.backgroundColor = "#064e3b";
        secHeader.style.borderRadius = "4px";
        secHeader.style.marginBottom = "8px";
        stmtCol.appendChild(secHeader);

        recommendedStatements.forEach(stmt => appendStatementItem(stmt, true));
      }

      if (remainingStatements.length > 0) {
        const secHeader = document.createElement("div");
        secHeader.innerText = "📄 सभी बैंक स्टेटमेंट ट्रांजेक्शन";
        secHeader.style.padding = "4px 8px";
        secHeader.style.fontSize = "11px";
        secHeader.style.fontWeight = "bold";
        secHeader.style.color = "#cbd5e1";
        secHeader.style.backgroundColor = "#0f172a";
        secHeader.style.borderRadius = "4px";
        secHeader.style.marginTop = recommendedStatements.length > 0 ? "10px" : "0px";
        secHeader.style.marginBottom = "8px";
        stmtCol.appendChild(secHeader);

        remainingStatements.forEach(stmt => appendStatementItem(stmt, false));
      }

      if (recommendedStatements.length === 0 && remainingStatements.length === 0) {
        const noData = document.createElement("div");
        noData.innerText = "कोई स्टेटमेंट रिकॉर्ड नहीं मिला।";
        noData.style.padding = "20px";
        noData.style.textAlign = "center";
        noData.style.color = "#94a3b8";
        noData.style.fontSize = "13px";
        stmtCol.appendChild(noData);
      }
    };

    let lastAutoMatchedAmount = null;
    const checkAndAutoSearch = () => {
      const pageAmount = getPageAmount();
      if (pageAmount && pageAmount !== lastAutoMatchedAmount) {
        lastAutoMatchedAmount = pageAmount;
        const match = statementRecords.find(stmt => cleanAmountStr(stmt.amount) === pageAmount);
        if (match && match.name && match.name !== "—") {
          searchInput.value = match.name;
          renderList(match.name);
          return;
        }
      }
      renderList(searchInput.value);
    };

    const currentInputs = getPaymentFormInputs();
    if (currentInputs.amount) {
      currentInputs.amount.addEventListener("input", checkAndAutoSearch);
      currentInputs.amount.addEventListener("change", checkAndAutoSearch);
    }

    searchInput.addEventListener("input", (e) => {
      renderList(e.target.value);
    });

    const footer = document.createElement("div");
    footer.style.padding = "10px 16px";
    footer.style.backgroundColor = "#0f172a";
    footer.style.borderTop = "1px solid #334155";
    footer.style.fontSize = "11px";
    footer.style.color = "#94a3b8";
    footer.style.textAlign = "center";
    footer.innerText = "सिंक करने के लिए लोकल ऐप में 'Sync with Extension' दबाएं।";
    container.appendChild(footer);

    // Inject inline below the form
    const form = document.querySelector("form");
    if (form) {
      form.parentElement.appendChild(container);
    } else {
      document.body.appendChild(container);
    }

    checkAndAutoSearch();
  });
}

